import pThrottle from 'p-throttle';

function rateLimitSlidingWindow(fn: (...args: unknown[]) => unknown, limit: number, interval: number): (...args: unknown[]) => Promise<unknown> {
  const throttled = pThrottle({ limit, interval })(fn);
  return throttled;
}

export { rateLimitSlidingWindow };
export default rateLimitSlidingWindow;
